mapper.select:
SELECT l.*, ste.site_nm AS site_nm, mem.member_nm AS member_nm, prd.prod_nm AS target_nm, cd_ltt.code_label AS target_type_cd_nm FROM mb_like l LEFT JOIN sy_site ste ON ste.site_id = l.site_id LEFT JOIN mb_member mem ON mem.member_id = l.member_id LEFT JOIN pd_prod prd ON prd.prod_id = l.target_id LEFT JOIN sy_code cd_ltt ON cd_ltt.code_grp = 'LIKE_TARGET_TYPE' AND cd_ltt.code_value = l.target_type_cd
ORDER BY l.like_id ASC ORDER BY l.like_id DESC ORDER BY l.reg_date ASC ORDER BY l.reg_date DESC ORDER BY l.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

SELECT l.*, ste.site_nm AS site_nm, mem.member_nm AS member_nm, prd.prod_nm AS target_nm, cd_ltt.code_label AS target_type_cd_nm FROM mb_like l LEFT JOIN sy_site ste ON ste.site_id = l.site_id LEFT JOIN mb_member mem ON mem.member_id = l.member_id LEFT JOIN pd_prod prd ON prd.prod_id = l.target_id LEFT JOIN sy_code cd_ltt ON cd_ltt.code_grp = 'LIKE_TARGET_TYPE' AND cd_ltt.code_value = l.target_type_cd
ORDER BY l.like_id ASC ORDER BY l.like_id DESC ORDER BY l.reg_date ASC ORDER BY l.reg_date DESC ORDER BY l.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

mapper.update:
UPDATE mb_like
site_id = #{siteId}, member_id = #{memberId}, target_type_cd = #{targetTypeCd}, target_id = #{targetId}, upd_by = #{updBy}, upd_date = #{updDate},
WHERE like_id = #{likeId}
